var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"니노마에 이나니스는 그녀의 시청자, 타코다치를 위해 직접 쓴 편지를 낭독하기로 했다.","JPN":"一伊那尓栖は彼女のリスナー、Takodachiのために自筆の手紙を朗読すると決めた。","ENG":"Ninomae Ina’nis decided to read a special letter that she has written for her loyal viewers, Takodachis.","TWN":"Ninomae Ina’nis decided to read a special letter that she has written for her loyal viewers, Takodachis."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"곧, 그녀가 무대 뒤에 도착했다는 무전이 들려왔다.","JPN":"先ほど、彼女がバックステージに着いたとの連絡があった。","ENG":"Soon, a radio call arrived saying that she has arrived backstage.","TWN":"Soon, a radio call arrived saying that she has arrived backstage."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EDEL_ESPR_CLB_003","text":{"KOREA":"WAH!","JPN":"WAH!","ENG":"WAH!","TWN":"WAH!"},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_CLB_003","face":"UNIT_SERIOUS"},"R":null}},"voice":"clb003_lifetime_voice_301"},{"id":"L9_1","type":"dialog","speaker":"EDEL_ESPR_CLB_003","text":{"KOREA":"아하하. 놀랐어?","JPN":"へへ、驚いた？","ENG":"Heheh, surprised?","TWN":"Heheh, surprised?"},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_CLB_003","face":"UNIT_LAUGH"},"R":null}},"voice":"clb003_lifetime_voice_302"},{"id":"L10_1","type":"dialog","speaker":"EDEL_ESPR_CLB_003","text":{"KOREA":"늘 그랬듯 모든 타코다치에게 인사하고 싶었어.","JPN":"いつものようにあなたに挨拶したかったの。","ENG":"Just wanted to greet all the Takodachis like always.","TWN":"Just wanted to greet all the Takodachis like always."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_CLB_003","face":"UNIT_IDLE"},"R":null}},"voice":"clb003_lifetime_voice_303"},{"id":"L11_1","type":"dialog","speaker":"EDEL_ESPR_CLB_003","text":{"KOREA":"이 순간은 항상 떨리더라. 하아…. 좋아, 진정된 것 같아. 한번 해 보자.","JPN":"この瞬間だけは、いつもドキドキするんだよね。はぁ……ちょっと落ち着いた。よし、やってみよう。","ENG":"These moments always make me nervous. Haah…. Right, Ok. Here we go.","TWN":"These moments always make me nervous. Haah…. Right, Ok. Here we go."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_CLB_003","face":"UNIT_PRIDE"},"R":null}},"voice":"clb003_lifetime_voice_304"},{"id":"L12_1","type":"dialog","speaker":"EDEL_ESPR_CLB_003","text":{"KOREA":"너를 위해 쓴 이 짤막한 편지를 읽을 거야! 이번에는 반드시 끝까지 읽고 말겠어!","JPN":"今からあなたの為に書いたこの短い手紙を読むよ。今度こそ最後まで読み切るからね。","ENG":"I am going to read a short letter I have written for you guys! Surely I can make it to the end this time!","TWN":"I am going to read a short letter I have written for you guys! Surely I can make it to the end this time!"},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_CLB_003","face":"UNIT_SERIOUS"},"R":null}},"voice":"clb003_lifetime_voice_305"},{"id":"L13_1","type":"dialog","speaker":"EDEL_ESPR_CLB_003","text":{"KOREA":"에헴… 타코다치에게.","JPN":"えへん……親愛なるTakodachiへ。","ENG":"Ahem… Dear Takodachis.","TWN":"Ahem… Dear Takodachis."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_CLB_003","face":"UNIT_IDLE"},"R":null}},"voice":"clb003_lifetime_voice_306"},{"id":"L14_1","type":"dialog","speaker":"EDEL_ESPR_CLB_003","text":{"KOREA":"안녕, 나는 이나야. 물론 알고 있겠지만.","JPN":"こんにちは。イナです。もちろんわかってると思うけど。","ENG":"Hi, I’m Ina. But you all know who I am.","TWN":"Hi, I’m Ina. But you all know who I am."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_CLB_003","face":"UNIT_IDLE"},"R":null}},"voice":"clb003_lifetime_voice_307"},{"id":"L15_1","type":"dialog","speaker":"EDEL_ESPR_CLB_003","text":{"KOREA":"이곳에 있는 동안 시간이 너무 빨리 지나가서 네가 시간 여행이라도 하는 줄 알았어!","JPN":"ここにいる間、時間の流れが速すぎてあなたがタイムスリップしているように見えたの！","ENG":"Time zoomed by so fast when I was here that it felt like as if you guys time travelled!","TWN":"Time zoomed by so fast when I was here that it felt like as if you guys time travelled!"},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_CLB_003","face":"UNIT_IDLE"},"R":null}},"voice":"clb003_lifetime_voice_308"},{"id":"L16_1","type":"dialog","speaker":"EDEL_ESPR_CLB_003","text":{"KOREA":"혹시 아메의 시계를 몰래 가져온 건 아니지?","JPN":"ひょっとして、アメの時計を盗んではないよね？","ENG":"Did you maybe steal Ame’s watch?","TWN":"Did you maybe steal Ame’s watch?"},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_CLB_003","face":"UNIT_SERIOUS"},"R":null}},"voice":"clb003_lifetime_voice_309"},{"id":"L17_1","type":"dialog","speaker":"EDEL_ESPR_CLB_003","text":{"KOREA":"헤헷, 내가 항상 하는 말이 있잖아. 재밌는 걸 하다 보면 시간이 순식간에 지나간다고!","JPN":"へへ、私がいつも言ってるよね。楽しいことをやっていると、時間が早く過ぎていくって。","ENG":"Hehe, but you know what I always say. Time flies when you're having fun!","TWN":"Hehe, but you know what I always say. Time flies when you're having fun!"},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_CLB_003","face":"UNIT_LAUGH"},"R":null}},"voice":"clb003_lifetime_voice_310"},{"id":"L18_1","type":"dialog","speaker":"EDEL_ESPR_CLB_003","text":{"KOREA":"여기 있는 동안 재밌고 신나는 경험을 많이 했어.","JPN":"ここにいる間たくさんの楽しい思い出を作ったよ。","ENG":"I experienced a lot of fun and exciting things while I was here.","TWN":"I experienced a lot of fun and exciting things while I was here."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_CLB_003","face":"UNIT_IDLE"},"R":null}},"voice":"clb003_lifetime_voice_311"},{"id":"L19_1","type":"dialog","speaker":"EDEL_ESPR_CLB_003","text":{"KOREA":"너는 어땠을까? 너도 나처럼 좋은 시간을 보냈기를 바라!","JPN":"あなたはどうだったかな？　私のように楽しい時間を過ごせたならいいな。","ENG":"How about you guys? Hope you all had a wonderful time too!","TWN":"How about you guys? Hope you all had a wonderful time too!"},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_CLB_003","face":"UNIT_IDLE"},"R":null}},"voice":"clb003_lifetime_voice_312"},{"id":"L20_1","type":"dialog","speaker":"EDEL_ESPR_CLB_003","text":{"KOREA":"네게 무한한 응원을 받은 것처럼, 내 소중한 타코다치에게 내가 보내는 응원과 사랑이 닿기를 기도할게.","JPN":"いつものあなたが支えてくれたように、私の大切なTakodachiにも私が送る愛と声援が届くことを願うよ。","ENG":"Just like how I got unlimited support from all of you guys, my dear Takodachis, I hope my love and support would reach you guys as well.","TWN":"Just like how I got unlimited support from all of you guys, my dear Takodachis, I hope my love and support would reach you guys as well."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_CLB_003","face":"UNIT_IDLE"},"R":null}},"voice":"clb003_lifetime_voice_313"},{"id":"L21_1","type":"dialog","speaker":"EDEL_ESPR_CLB_003","text":{"KOREA":"모두 함께 응원한다면 그 어떤 역경이라도 헤쳐 나갈 수 있다고 믿거든!","JPN":"みんなの応援があれば、どんな逆境も乗り越えられるって信じているから！","ENG":"I am sure with everyone's support we can get through the hardest challenges!","TWN":"I am sure with everyone's support we can get through the hardest challenges!"},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_CLB_003","face":"UNIT_PRIDE"},"R":null}},"voice":"clb003_lifetime_voice_314"},{"id":"L22_1","type":"dialog","speaker":"EDEL_ESPR_CLB_003","text":{"KOREA":"만약 실패하더라도 <color=#ffd34c>다음!</color>을 외치며 나아가는 거야!","JPN":"もし挫けたとしても、「次！」って言いながら前に進もう！","ENG":"Even when we fail, we'll shout GO NEXT! and move on!","TWN":"Even when we fail, we'll shout GO NEXT! and move on!"},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_CLB_003","face":"UNIT_IDLE"},"R":null}},"voice":"clb003_lifetime_voice_315"},{"id":"L23_1","type":"dialog","speaker":"EDEL_ESPR_CLB_003","text":{"KOREA":"인생이라는 험난하고 가파른 산을 올라야 하지만, 산 정상에서 바라보는 풍경은 그 어떤 것보다 아름다울 거야. 네가 내 곁에 있을 거니까!","JPN":"人生という高い山を登るのはそう簡単じゃないと思うよ。でも、頂上から見渡す景色は、きっとこの世の何よりも美しいはずよ。私もその場に一緒にいてあげるからね！","ENG":"It's a steep climb up the mountain called life, but I'm sure the view from the top will be unforgettable especially with you guys by my side!","TWN":"It's a steep climb up the mountain called life, but I'm sure the view from the top will be unforgettable especially with you guys by my side!"},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_CLB_003","face":"UNIT_LAUGH"},"R":null}},"voice":"clb003_lifetime_voice_316"}]`);export{e as default};